def was_top_three_seeded(player_name: str) -> bool:
    top_three_men = {
        'Nikolay Davydenko',
        'Fernando González',
        'Tommy Robredo'
    }
    return player_name in top_three_men

This function returns `True` if the player was one of the top three seeded men's singles players at the 2007 China Open, otherwise it returns `False`.
